	INSERT INTO sys_user (id, name, username,sys_dept_id,`password`,sys_group_id,status,state)  
	insert into sys_dept (id,name,status,parent_id) select ORGAN_NO, ORGAN_NAME,'1',Parent_Organ  FROM sm_organ_tb2 b  where b.organ_no not in (select id from sys_dept) and b.ORGan_NO  in (select Parent_OrgAN from sm_organ_tb2 GROUP BY  Parent_OrgAN) ;
