-- ----------------------------
-- Procedure structure for afterStartInit
-- ----------------------------
DROP PROCEDURE IF EXISTS `afterStartInit`;
delimiter ;;
CREATE PROCEDURE `afterStartInit`()
BEGIN
		-- 项目启动后，执行，把序号赋值到id上
	update  fl_flow_tb f set f.id=f.SEQ_ID ,status='1',sys_dept_id=SITE_NO ,sys_user_id=OPERATOR_NO where id is null;
	
	update  bp_tmpbatch_tb f set f.id=f.BATCH_ID ,status='1',sys_dept_id=SITE_NO ,sys_user_id=OPERATOR_NO  where id is null;
	-- 外键字段赋值，状态赋值
	update  bp_tmpdata_1_tb f set f.bank_flow_id=f.SERIAL_NO ,status='1',f.id= CONCAT(SERIAL_NO,
	
	CONCAT('-', ROUND(f.INCCODEIN_BATCH, 0) )); 

END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for assign_codes
-- ----------------------------
DROP PROCEDURE IF EXISTS `assign_codes`;
delimiter ;;
CREATE PROCEDURE `assign_codes`()
BEGIN  

		DECLARE v_code VARCHAR(20);  
    DECLARE v_pcode VARCHAR(20);  
    DECLARE v_depth INT;  
    DECLARE pcode_cursor CURSOR FOR SELECT pcode FROM sys_dept;  
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET @done = TRUE;  
    DECLARE CONTINUE HANDLER FOR SQLSTATE '42S22' SET @done = TRUE;  
  
    OPEN pcode_cursor;  
    pcode_loop: LOOP  
        FETCH pcode_cursor INTO v_pcode;  
        IF  @done THEN  
            LEAVE pcode_loop;  
        END IF;  
  
       
        UPDATE sys_dept SET code = CONCAT(SUBSTRING(pcode, INSTR(pcode, '_') + 1), '__', LPAD(SUBSTRING(pcode, INSTR(pcode, '_') + 1), 3, '0')), pcode = SUBSTRING(pcode, INSTR(pcode, '_') + 1) WHERE parent_id = v_pcode AND LENGTH(code) = 0;  
    END LOOP;  
    CLOSE pcode_cursor;  
   
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for beforeStartInit
-- ----------------------------
DROP PROCEDURE IF EXISTS `beforeStartInit`;
delimiter ;;
CREATE PROCEDURE `beforeStartInit`()
BEGIN
-- 银行用户创建vlife用户
	delete from sys_user where username not in ('admin','manage');

	SELECT ORGAN_NO, ORGAN_NAME, CONCAT('user_',ORGAN_NO),Parent_OrgAN,'{b071kNp38xQB0/0gdcuQ4T/zQ+UaeqfoJ8hbnd1dQmk=}3e97fc97aab0b5d2ab1de86c8aca4c8c','worker','1','1'
	FROM sm_organ_tb2 b  where b.organ_no not in (select id from sys_user) and  b.ORGan_NO not in (select Parent_OrgAN from sm_organ_tb2 GROUP BY  Parent_OrgAN) ;


	-- 为部门组织创建用户 
	SELECT ORGAN_NO, ORGAN_NAME, CONCAT('bank_',ORGAN_NO),ORGan_NO,'{b071kNp38xQB0/0gdcuQ4T/zQ+UaeqfoJ8hbnd1dQmk=}3e97fc97aab0b5d2ab1de86c8aca4c8c','leader','1','1'
	FROM sm_organ_tb2 b  where b.organ_no not in (select id from sys_user) and b.ORGan_NO  in (select Parent_OrgAN from sm_organ_tb2 GROUP BY  Parent_OrgAN) ;


	delete from sys_dept where create_date is null;

	-- 创建部门 为部门编号
	
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for delete_status_zero
-- ----------------------------
DROP PROCEDURE IF EXISTS `delete_status_zero`;
delimiter ;;
CREATE PROCEDURE `delete_status_zero`()
BEGIN
-- 物理删除已经逻辑删除得数据
    delete from form where status='0';
    delete from form_field where status='0';
    delete from sys_menu where status='0';
    delete from sys_user where status='0';
    delete from sys_menu where status='0';
    delete from page_api_param where status='0';
    delete from page_component where status='0';
    delete from page_component_prop where status='0';
    delete from sys_file where status='0';
    delete from sys_reources where status='0';
    delete from form_tab where status='0';
    delete from form_reaction where status='0';
    delete from sys_dept where status='0';
    delete from sys_group where status='0';
    delete from sys_role where status='0';
    delete from sys_role_group where status='0';
-- 		清空业务数据
		delete from erp_customer;
		delete from erp_linkman;		
		delete from erp_product;		
		delete from erp_supplier;		
		delete from erp_order_sale;
		delete from erp_order_purchase;
		delete from erp_order_sale_detail;
		delete from erp_order_purchase_detail;	
--  主表删除子表没删除的（手工删除后续操作）
		delete from form_field where form_id not in (select id from form);
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for initBankData
-- ----------------------------
DROP PROCEDURE IF EXISTS `initBankData`;
delimiter ;;
CREATE PROCEDURE `initBankData`()
BEGIN
-- 银行用户创建vlife用户
	delete from sys_user where username not in ('admin','manage');



	SELECT ORGAN_NO, ORGAN_NAME, CONCAT('user_',ORGAN_NO),Parent_OrgAN,'{b071kNp38xQB0/0gdcuQ4T/zQ+UaeqfoJ8hbnd1dQmk=}3e97fc97aab0b5d2ab1de86c8aca4c8c','worker','1','1'
	FROM sm_organ_tb2 b  where b.organ_no not in (select id from sys_user) and  b.ORGan_NO not in (select Parent_OrgAN from sm_organ_tb2 GROUP BY  Parent_OrgAN) ;


	-- 为部门组织创建用户 
	SELECT ORGAN_NO, ORGAN_NAME, CONCAT('bank_',ORGAN_NO),ORGan_NO,'{b071kNp38xQB0/0gdcuQ4T/zQ+UaeqfoJ8hbnd1dQmk=}3e97fc97aab0b5d2ab1de86c8aca4c8c','super','1','1'
	FROM sm_organ_tb2 b  where b.organ_no not in (select id from sys_user) and b.ORGan_NO  in (select Parent_OrgAN from sm_organ_tb2 GROUP BY  Parent_OrgAN) ;


	delete from sys_dept where create_date is null;

	-- 创建部门 为部门编号
	
	-- 项目启动后，执行，把序号赋值到id上
	update  fl_flow_tb f set f.id=f.SEQ_ID ,status='1';

END
;;
delimiter ;

